// Skip screening: pass articles through with default Maybe decision
const articles = $('Input').all().map(i => i.json);
console.log('Screening SKIPPED: ' + articles.length + ' articles passed through with decision=Maybe');
return articles.map(a => ({ json: { ...a, screening_decision: 'Maybe', screening_reason: 'Screening skipped by user', screening_color: 'orange' } }));

// SCREENING_REASON_PRISMA_v3
// SCREENING_REASON_PRISMA_v1
// SCREENING_CONFIDENCE_v1
// === SCREENING v3 - Prompt simplifie + batches reduits ===
// PATCH v2 : abstract-missing -> Maybe (no LLM call)
const items = $input.all();
const articles = items.map(i => i.json);
const BATCH_SIZE = 1;
const MIN_ABSTRACT_LEN = 50;  // < 50 chars = pas exploitable -> Maybe direct
const question = (articles[0] && articles[0].question) || '';
const criteria = (articles[0] && articles[0].criteria) || '';
let aiSettings = (articles[0] && articles[0]._ai_settings) || {};
if (typeof aiSettings.strictness !== 'number') { try { const __ac = await this.helpers.httpRequest({ method:'GET', url:'http://host.docker.internal:8080/api/config', timeout:5000, json:true }) || {}; aiSettings = { strictness: __ac.screening_strictness, custom_rules: __ac.screening_custom_rules }; } catch(e) {} } // AI_SETTINGS_CONFIG_FALLBACK_v1
const strictness = (typeof aiSettings.strictness === 'number') ? aiSettings.strictness : 50;
const customRules = (aiSettings.custom_rules || '').toString().trim();
let strictnessGuidance = '';
if (strictness <= 25) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe CONSERVATIVE: when in doubt, prefer Include or Maybe over Exclude. The user wants to capture as many potentially relevant articles as possible at this stage.';
} else if (strictness >= 75) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe STRICT: only mark Include if all criteria are clearly met. When in doubt, prefer Exclude. The user wants a tightly filtered set of highly relevant articles.';
} else if (strictness >= 60) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe slightly strict: when in doubt, lean toward Exclude rather than Maybe.';
} else if (strictness <= 40) {
  strictnessGuidance = '\n\n=== TONE GUIDANCE ===\nBe slightly conservative: when in doubt, lean toward Maybe rather than Exclude.';
}
const customRulesBlock = customRules
  ? '\n\n=== USER-DEFINED RULES (must be respected) ===\n' + customRules
  : '';
const batches = [];

function sanitize(text) {
  return (text || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();
}

// PATCH v2 : pre-filtrer les articles SANS abstract exploitable.
// Ces articles sortiront avec Maybe directement (pas d'appel LLM = economie + bonne logique).
// On garde leur index global pour que Expand Results puisse les retrouver.
let llmEligibleCount = 0;
let skippedNoAbstract = 0;
for (let i = 0; i < articles.length; i++) {
  const abs = sanitize(articles[i].abstract || '');
  if (abs.length < MIN_ABSTRACT_LEN) {
    skippedNoAbstract++;
  } else {
    llmEligibleCount++;
  }
}
console.log('Screening v3 PATCH v2: ' + articles.length + ' articles total, ' +
            llmEligibleCount + ' avec abstract exploitable, ' +
            skippedNoAbstract + ' sans abstract (-> Maybe direct, pas d\'appel LLM).');

// Generation des batches SEULEMENT pour les articles avec abstract exploitable.
// On stocke aussi la liste des global_indexes pour que Expand Results sache de quel article il s'agit.
let pendingBatch = [];
let pendingIndexes = [];

// === ULTRALAB_SCREENING_V4_TEXT - format reponse texte simple (anti batch failed) ===
// REASON_FORMAT_INSISTENCE_v7 - consigne 'no blank line' injectee dans le prompt
function flushBatch() {
  if (pendingBatch.length === 0) return;
  // Pour BATCH_SIZE=1, on prend l'article unique. Pour back-compat BATCH > 1, on concatene.
  const articleList = pendingBatch.map((a, j) => {
    const title = sanitize(a.title || 'No title').substring(0, 120);
    const abstract = sanitize(a.abstract || '').substring(0, 800);
    return 'TITLE: ' + title + '\nABSTRACT: ' + abstract;
  }).join('\n\n---\n\n');

  const prompt = 'You are a systematic review screener. Choose ONE decision for the article below: Include, Maybe, or Exclude.\n\n' +
    'RESEARCH QUESTION:\n' + sanitize(question).substring(0, 500) + '\n\n' +
    'INCLUSION/EXCLUSION CRITERIA:\n' + sanitize(criteria).substring(0, 500) + '\n\n' +
    '=== ARTICLE ===\n' + articleList + '\n\n' +
    '=== DECISION RULES ===\n' +
    '- Include = ALL inclusion criteria clearly met AND no exclusion criterion applies\n' +
    '- Maybe = at least one criterion is unclear from the abstract OR abstract is too brief\n' +
    '- Exclude = clearly fails at least one inclusion criterion OR clearly meets an exclusion criterion\n\n' +
    'When the abstract is missing or very short: ALWAYS choose Maybe.\n' +
    'When uncertain: Maybe (be inclusive at this stage).' + strictnessGuidance + customRulesBlock + '\n\n' +
    '=== REASON REQUIREMENTS (PRISMA-grade, mandatory) ===\n- Name the SPECIFIC inclusion or exclusion criterion that drove the decision (quote the criterion).\n- Cite the concrete evidence FROM THE ABSTRACT that supports it: population, intervention/exposure, comparator, outcome, and/or study design as relevant.\n- If you Exclude, name the concrete disqualifier visible in the abstract (for example: it is a review or meta-analysis; it is a single-patient case report; it is an animal or preclinical study; the population is children; the primary indication is diabetes rather than obesity) and the abstract wording that proves it. If Maybe, state precisely what is missing or unclear in the abstract.\n- FORBIDDEN (not acceptable): vague or circular reasons such as: matches the criteria / clearly relevant / fits the research question / meets inclusion criteria / fails an inclusion criterion / clearly meets an exclusion criterion / fails at least one criterion. Repeating the rubric wording is NOT a reason. A reason that does not name the criterion AND point to abstract evidence is invalid.\n- Keep it to 1-2 specific, auditable sentences on a SINGLE line.\n\n=== OUTPUT FORMAT (STRICT) ===\nOutput ONLY the following four lines, nothing before or after them. Begin with the word Decision.\nLine 1 = Decision: then your verdict, which is exactly one of Include, Maybe or Exclude.\nLine 2 = Reason: then ONE sentence that names the exact inclusion or exclusion criterion you applied AND states the concrete fact from the abstract above that triggered it (population, study design, intervention or outcome).\nLine 3 = Confidence: then exactly one of high, medium or low. This line is mandatory and must never be omitted.\nLine 4 = Criteria: then a per-criterion audit of the inclusion and exclusion criteria, writing each criterion as a short label followed by = and one of met, unmet or unclear, separated by semicolons (for example Population=met; Study design=unmet; Outcome=unclear). Cover every criterion you can identify in the criteria text above. This line is required.\nDo NOT copy wording from these instructions or from the criteria list; describe only what THIS abstract actually says. The Reason must be consistent with the Decision (never write Exclude wording when the Decision is Include). No markdown, no numbering, no extra commentary.';

  batches.push({ json: {
    prompt: prompt,
    batchIndex: batches.length,
    batchSize: pendingBatch.length,
    global_indexes: pendingIndexes.slice()
  }});
  pendingBatch = [];
  pendingIndexes = [];
}


for (let i = 0; i < articles.length; i++) {
  const abs = sanitize(articles[i].abstract || '');
  if (abs.length < MIN_ABSTRACT_LEN) continue;  // skip, sera traite par Expand Results
  pendingBatch.push(articles[i]);
  pendingIndexes.push(i);
  if (pendingBatch.length >= BATCH_SIZE) flushBatch();
}
flushBatch();

console.log('Screening v3 PATCH v2: ' + batches.length + ' batches LLM construits (skip ' + skippedNoAbstract + ' articles).');
return batches;

// === SCREENING v4 ROBUST - Parser texte tolerant + Retry x2 + Diag enrichi (2026-06-01) ===
// Strategies cumulees : prompt format texte simple, parser tolerant, retry inline,
// diag enrichi avec raw LLM preserve dans screening_reason en cas d'echec final.

const responses = $input.all();
const originalItems = $('Input').all();
const prepBatches = $('Prepare Batches').all();
const articles = originalItems.map(i => i.json);
const MIN_ABSTRACT_LEN = 50;
const colorMap = { 'Include': 'green', 'Maybe': 'orange', 'Exclude': 'red' };
const RETRY_MAX = 2;

const question = (articles[0] && articles[0].question) || '';
const criteria = (articles[0] && articles[0].criteria) || '';

function sanitize(text) {
  return (text || '').replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, ' ').replace(/\s+/g, ' ').trim();
}

// === PARSER TEXTE TOLERANT ===
// Cherche "Decision: <X>" puis "Reason: ...", avec multiples fallbacks.
function parseTextDecision(raw) {
  if (!raw || typeof raw !== 'string') return null;
  const text = raw.trim();

  // Tentative 1 : cherche "Decision: <X>" insensible a la casse
  const decMatch = text.match(/decision\s*[:=]\s*(include|maybe|exclude)/i);
  let decision = null, reason = '';
  if (decMatch) {
    decision = decMatch[1].charAt(0).toUpperCase() + decMatch[1].slice(1).toLowerCase();
    // Recuperer "Reason:" sur les lignes suivantes
    const reasonMatch = text.match(/reason\s*[:=]\s*([\s\S]{0,400})/i);
    if (reasonMatch) {
      reason = reasonMatch[1].split(/\n\n|\r\n\r\n/)[0].replace(/[\r\n]+\s*(confidence|decision)\s*[:=][\s\S]*$/i, '').replace(/\s+/g, ' ').trim().substring(0, 300);
    }
    return { decision, reason, source: 'text_parse' };
  }

  // Tentative 2 : premier match \b(Include|Maybe|Exclude)\b dans la reponse
  const fbMatch = text.match(/\b(Include|Maybe|Exclude)\b/i);
  if (fbMatch) {
    decision = fbMatch[1].charAt(0).toUpperCase() + fbMatch[1].slice(1).toLowerCase();
    // Reason : prendre le contexte qui suit
    const after = text.substring(text.indexOf(fbMatch[0]) + fbMatch[0].length);
    reason = after.replace(/[:.\s]+/, '').substring(0, 300).trim();
    if (!reason) reason = '(extracted from raw response - no explicit Reason field)';
    return { decision, reason, source: 'fallback_regex' };
  }

  // Tentative 3 : essayer aussi le format JSON ancien (back-compat)
  // si jamais le LLM repond en JSON
  try {
    const jsonMatch = text.match(/\{[\s\S]*?\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      if (parsed.decision) {
        const d = parsed.decision.toString().toLowerCase();
        if (d.startsWith('inc')) return { decision: 'Include', reason: parsed.reason || '', source: 'json_back_compat' };
        if (d.startsWith('exc')) return { decision: 'Exclude', reason: parsed.reason || '', source: 'json_back_compat' };
        if (d.startsWith('may')) return { decision: 'Maybe', reason: parsed.reason || '', source: 'json_back_compat' };
      }
      // Ancien format { decisions: [{...}] }
      if (Array.isArray(parsed.decisions) && parsed.decisions.length > 0) {
        const d = parsed.decisions[0];
        const dec = (d.decision || '').toString().toLowerCase();
        let dn = 'Maybe';
        if (dec.startsWith('inc')) dn = 'Include';
        else if (dec.startsWith('exc')) dn = 'Exclude';
        return { decision: dn, reason: d.reason || '', source: 'json_legacy_back_compat' };
      }
    }
  } catch (e) {}

  return null;
}

// === RETRY INLINE : si batch fail, re-call Ollama avec prompt minimal ===
async function retryOllamaCall(article, attempt) {
  const ab = sanitize(article.abstract || '').substring(0, 400);
  const ti = sanitize(article.title || '').substring(0, 120);
  // Prompt encore plus laconique pour le retry
  const prompt = 'Article title: ' + ti + '\n' +
                 'Abstract: ' + ab + '\n\n' +
                 'Research question: ' + sanitize(question).substring(0, 300) + '\n\n' +
                 'Reply with ONLY these 2 lines (no explanation, no markdown):\n' +
                 'Decision: Include OR Maybe OR Exclude\n' +
                 'Reason: one short sentence\n\n' +
                 'Choose Maybe when uncertain. Start immediately with "Decision:".';

  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'http://host.docker.internal:3456/api/generate',
      body: JSON.stringify({
        model: 'llama3.2:latest',
        stream: false,
        options: { temperature: 0, num_predict: 1500, num_ctx: 2048 },
        keep_alive: '30m',
        prompt: prompt,
        _ultralab_task: 'chat'
      }),
      headers: { 'Content-Type': 'application/json' },
      json: true,
      timeout: 180000
    });
    return resp && resp.response ? resp.response : '';
  } catch (e) {
    return '';
  }
}

// === BOUCLE PRINCIPALE : match response <-> article via prepBatches ===
const decisionByArticleIdx = new Map();
const rawByArticleIdx = new Map();
const retryStatsByArticleIdx = new Map();
let okBatches = 0, parseFailedBatches = 0, retrySuccessful = 0, retryFailed = 0;
const diagnostics = [];

for (let r = 0; r < responses.length; r++) {
  const resp = responses[r].json || {};
  const prepItem = prepBatches[r] && prepBatches[r].json ? prepBatches[r].json : {};
  const globalIndexes = Array.isArray(prepItem.global_indexes) ? prepItem.global_indexes : null;
  const batchIdx = (resp.batchIndex !== undefined) ? resp.batchIndex : r;
  const batchSize = prepItem.batchSize || resp.batchSize || 1;

  const rawText = (resp.response || '').toString();
  let parsed = parseTextDecision(rawText);
  let attempt = 1;
  let lastRaw = rawText;

  // Retry x2 si parse fail
  while (!parsed && attempt <= RETRY_MAX && globalIndexes && globalIndexes.length === 1) {
    const articleIdx = globalIndexes[0];
    const article = articles[articleIdx];
    if (!article) break;
    const retryRaw = await retryOllamaCall.call(this, article, attempt);
    lastRaw = retryRaw || lastRaw;
    parsed = parseTextDecision(retryRaw);
    attempt++;
    if (parsed) retrySuccessful++;
  }

  if (parsed) {
    okBatches++;
  } else {
    parseFailedBatches++;
    if (attempt > 1) retryFailed++;
  }

  // Mapping : pour BATCH_SIZE=1, globalIndexes a 1 element
  // Pour back-compat avec ancien BATCH_SIZE > 1, on supporte multiple
  if (globalIndexes && globalIndexes.length > 0) {
    // Pour le format texte simple, 1 batch = 1 article, donc 1 decision pour le seul article du batch
    const articleIdx = globalIndexes[0];
    rawByArticleIdx.set(articleIdx, {
      raw_preview: (lastRaw || 'no response').substring(0, 300),
      parse_status: parsed ? 'ok' : 'parse_failed',
      attempt: attempt - 1,
      source: parsed ? parsed.source : 'no_parse'
    });
    if (parsed) {
      decisionByArticleIdx.set(articleIdx, {
        decision: parsed.decision,
        reason: parsed.reason || '(no reason returned)',
        confidence: (function(t){ var m = (t || '').match(/confidence\s*[:=]\s*(high|medium|low)/i); return m ? m[1].toLowerCase() : ''; })(lastRaw),
        criteria: (function(t){ var m2 = (t || '').match(/criteria\s*[:=]\s*([^\n]{0,300})/i); return m2 ? m2[1].replace(/\s+/g, ' ').trim() : ''; })(lastRaw)
      });
    }
    // Pour les autres articles du batch (si jamais BATCH_SIZE > 1), enregistrer comme echec
    if (!parsed && globalIndexes.length > 1) {
      for (let k = 1; k < globalIndexes.length; k++) {
        const gi = globalIndexes[k];
        if (!rawByArticleIdx.has(gi)) {
          rawByArticleIdx.set(gi, {
            raw_preview: (lastRaw || 'no response').substring(0, 300),
            parse_status: 'parse_failed',
            attempt: attempt - 1,
            source: 'no_parse'
          });
        }
      }
    }
  } else {
    // Fallback : ordre sequentiel
    const fallbackIdx = batchIdx * batchSize;
    if (parsed && fallbackIdx < articles.length) {
      decisionByArticleIdx.set(fallbackIdx, {
        decision: parsed.decision,
        reason: parsed.reason || '(no reason returned)'
      });
    }
    rawByArticleIdx.set(fallbackIdx, {
      raw_preview: (lastRaw || 'no response').substring(0, 300),
      parse_status: parsed ? 'ok' : 'parse_failed',
      attempt: attempt - 1,
      source: parsed ? parsed.source : 'no_parse'
    });
  }

  if (!parsed) {
    diagnostics.push('Article idx ' + (globalIndexes ? globalIndexes[0] : batchIdx * batchSize) +
      ' - parse failed after ' + (attempt - 1) + ' retries. Raw[0:120]: ' +
      lastRaw.substring(0, 120).replace(/\s+/g, ' '));
  }
}

// === Construction du resultat final ===
const results = [];
let totalInc = 0, totalExc = 0, totalMay = 0;
let skippedNoAbstract = 0;

for (let i = 0; i < articles.length; i++) {
  const article = articles[i];
  const abs = sanitize(article.abstract || '');
  const llmResult = decisionByArticleIdx.get(i);
  let decision, reason;

  if (abs.length < MIN_ABSTRACT_LEN) {
    decision = 'Maybe';
    reason = abs.length === 0
      ? 'Abstract absent - decision Maybe par defaut (article non excluable sur titre seul)'
      : 'Abstract trop court (' + abs.length + ' chars) - decision Maybe par defaut';
    skippedNoAbstract++;
  } else if (llmResult) {
    decision = llmResult.decision;
    reason = llmResult.reason;
  } else {
    // Article cense etre traite par LLM mais pas de resultat (apres tous les retries)
    decision = 'Maybe';
    const rawInfo = rawByArticleIdx.get(i);
    let suffix = '';
    if (rawInfo) {
      const rp = (rawInfo.raw_preview || '').replace(/\s+/g, ' ').substring(0, 180);
      suffix = ' [retries: ' + (rawInfo.attempt || 0) + ' | LLM raw: ' + rp + ']';
    }
    reason = 'Batch LLM failed after retries - decision Maybe par defaut (a re-examiner manuellement)' + suffix;
  }


  // === INCLUDE_NEEDS_REASON_v1 - securite scientifique (2026-06-03) ===
  // Si le LLM a marque Include mais n'a pas fourni de justification verifiable,
  // on bascule en Maybe pour re-examen manuel (preserve la rigueur methodo).
  if (decision === 'Include' && (!reason || /^\(no reason|^\(no explicit|^\s*$/i.test(reason))) {
    decision = 'Maybe';
    reason = 'LLM a propose Include mais sans justification verifiable - reclasse Maybe pour verification manuelle';
  }
  if (decision === 'Include') totalInc++;
  else if (decision === 'Exclude') totalExc++;
  else totalMay++;

  results.push({
    json: {
      ...article,
      screening_decision: decision,
      screening_reason: reason,
      screening_confidence: (llmResult && llmResult.confidence) || '',
      screening_criteria: (llmResult && llmResult.criteria) || '',
      _needs_human_review: (decision === 'Maybe') || !!(llmResult && llmResult.confidence === 'low'),
      screening_color: colorMap[decision] || 'orange'
    }
  });
}

console.log('=== Screening v4 ROBUST complete ===');
console.log('Articles: ' + results.length + ' | Batches OK: ' + okBatches + ' | Batches KO: ' + parseFailedBatches);
console.log('Retries reussis: ' + retrySuccessful + ' | Retries echoues: ' + retryFailed);
console.log('Sans abstract (Maybe direct) : ' + skippedNoAbstract);
console.log('Decisions: Include=' + totalInc + ' Maybe=' + totalMay + ' Exclude=' + totalExc);
if (diagnostics.length > 0) {
  console.log('--- Diagnostics (premiers 5) ---');
  diagnostics.slice(0, 5).forEach(d => console.log(d));
}
return results;

// SCREENING_DOUBLE_KAPPA_v1 - 2e relecture (modele OBLIGATOIREMENT different) + Cohen's kappa, opt-in
const pass1 = $input.all().map(i => i.json);              // articles avec screening_decision (passe 1)
const prep  = $('Prepare Batches').all().map(i => i.json); // prompts + global_indexes (re-jouables)

// 1) Config double-relecture
let cfg = {};
try { cfg = await this.helpers.httpRequest({ method:'GET', url:'http://host.docker.internal:8080/api/config', timeout:5000, json:true }) || {}; } catch(e) { cfg = {}; }
const doubleEnabled = cfg.screening_double_enabled === true;
const model1 = (cfg.ollama_model || '').trim();
const model2 = (cfg.screening_model_2 || '').trim();

// Garde : OFF, ou modele 2 absent / identique au modele 1 -> pas de 2e passe (renvoi inchange)
if (!doubleEnabled || !model2 || model2 === model1) {
  const why = !doubleEnabled ? 'disabled' : (!model2 ? 'no_model2' : 'model2_equals_model1');
  console.log('Double screening SKIP (' + why + ')');
  return pass1.map(a => ({ json: Object.assign({}, a, { screening_double: why }) }));
}

// 2) Parser decision compact (aligne sur Expand Results)
function parseDec(raw){
  if(!raw) return null;
  const t = String(raw);
  let m = t.match(/decision\s*[:=]\s*(include|maybe|exclude)/i);
  if(!m) m = t.match(/\b(include|maybe|exclude)\b/i);
  if(!m) return null;
  const d = m[1].toLowerCase();
  return d.charAt(0).toUpperCase() + d.slice(1);
}

// 3) 2e passe : re-jouer les memes prompts avec le modele 2 (tag screening_pass2 -> proxy applique screening_model_2)
const dec2ByIdx = new Map();
let nCalls = 0, nCallFail = 0;
for (let r = 0; r < prep.length; r++){
  const p = prep[r] || {};
  const gi = (Array.isArray(p.global_indexes) && p.global_indexes.length) ? p.global_indexes[0] : null;
  if (gi === null || !p.prompt) continue;
  let raw = '';
  try {
    const resp = await this.helpers.httpRequest({
      method:'POST', url:'http://host.docker.internal:3456/api/generate',
      body: JSON.stringify({ model: model2, stream:false, options:{ temperature:0, stop:['\n\n\n','Article ','TITLE:','Article:'], num_predict:2000, num_ctx:6144 }, keep_alive:'30m', prompt: p.prompt, _ultralab_task:'screening_pass2' }),
      headers:{ 'Content-Type':'application/json' }, json:true, timeout:600000
    });
    raw = (resp && resp.response) ? resp.response : '';
    nCalls++;
  } catch(e) { raw = ''; nCallFail++; }
  const d = parseDec(raw);
  if (d) dec2ByIdx.set(gi, d);
}

// 4) Fusion + Cohen's kappa (3 categories)
const cats = ['Include','Maybe','Exclude'];
const c1 = { Include:0, Maybe:0, Exclude:0 };
const c2 = { Include:0, Maybe:0, Exclude:0 };
let nBoth = 0, nAgree = 0;
const out = pass1.map((a, idx) => {
  const d1 = a.screening_decision;
  const d2 = dec2ByIdx.has(idx) ? dec2ByIdx.get(idx) : null;
  const merged = Object.assign({}, a);
  if (d2) {
    merged.screening_decision_2 = d2;
    merged.screening_model2 = model2;
    const agree = (d1 === d2);
    merged.screening_agreement = agree ? 'agree' : 'disagree';
    if (!agree) merged._needs_human_review = true;   // desaccord -> arbitrage humain
    if (cats.indexOf(d1) >= 0 && cats.indexOf(d2) >= 0) { nBoth++; if (agree) nAgree++; c1[d1]++; c2[d2]++; }
  } else {
    merged.screening_decision_2 = '';
    merged.screening_agreement = '';
  }
  return merged;
});

let kappa = null;
if (nBoth > 0) {
  const po = nAgree / nBoth;
  let pe = 0;
  for (let k = 0; k < cats.length; k++){ const c = cats[k]; pe += (c1[c]/nBoth) * (c2[c]/nBoth); }
  kappa = (pe < 1) ? ((po - pe) / (1 - pe)) : 1;
}
const kappaR = (kappa === null) ? null : Math.round(kappa * 1000) / 1000;
function kLabel(k){ if(k===null) return 'n/a'; if(k<0) return 'poor'; if(k<=0.2) return 'slight'; if(k<=0.4) return 'fair'; if(k<=0.6) return 'moderate'; if(k<=0.8) return 'substantial'; return 'almost perfect'; }

const summary = { enabled:true, model_1:model1, model_2:model2, n_double_rated:nBoth, n_agree:nAgree, n_disagree:(nBoth-nAgree), percent_agreement: nBoth ? Math.round(nAgree/nBoth*1000)/10 : null, cohen_kappa:kappaR, kappa_interpretation:kLabel(kappaR) };
console.log('Double screening: kappa=' + kappaR + ' (' + summary.kappa_interpretation + '), accord ' + summary.percent_agreement + '% sur ' + nBoth + ' articles (' + model1 + ' vs ' + model2 + '), calls=' + nCalls + ' fail=' + nCallFail);

return out.map(a => ({ json: Object.assign(a, { screening_double: 'on', _screening_kappa: summary }) }));
